+	test("fromEnv reads stream read timeout from SPROUT_STREAM_READ_TIMEOUT_MS", () => {
+		const saved = process.env.SPROUT_STREAM_READ_TIMEOUT_MS;
+		process.env.SPROUT_STREAM_READ_TIMEOUT_MS = "120000";
